+// translateToAppleContainer translates Docker CLI args to Apple Container CLI
+func (c *Client) translateToAppleContainer(args []string) []string {
+	if len(args) == 0 {
+		return args
+	}
+
+	// Translate: ps -> ls
+	if args[0] == "ps" {
+		newArgs := []string{"ls"}
+		newArgs = append(newArgs, args[1:]...)
+		return newArgs
+	}
+
+	return args
+}
